// Prepare scenes array with cumulative tracking metadata
const scenes = $('Load Pending Scenes').first().json;
if (!Array.isArray(scenes) || scenes.length === 0) {
  return [{ json: { scenes: [], topic_id: $('Webhook Trigger').item.json.body.topic_id, total_scenes: 0 } }];
}

// Get the last completed scene's end_time_ms for resume support
// We'll query this separately; for now set initial cumulative to 0
return [{
  json: {
    scenes: scenes,
    topic_id: scenes[0].topic_id,
    project_id: scenes[0].project_id,
    total_scenes: scenes.length,
    current_index: 0,
    cumulative_end_time_ms: 0,
    scenes_completed: 0,
    scenes_failed: 0,
    total_cost: 0
  }
}];

// Set cumulative_end_time_ms from last completed scene (for resume support)
const lastCompleted = $input.first().json;
const prepData = $('Prepare Scene Loop').first().json;

let cumulativeMs = 0;
if (Array.isArray(lastCompleted) && lastCompleted.length > 0 && lastCompleted[0].end_time_ms) {
  cumulativeMs = lastCompleted[0].end_time_ms;
}

return [{
  json: {
    ...prepData,
    cumulative_end_time_ms: cumulativeMs
  }
}];

// Get current scene data from the batch
const batchItem = $('Loop Over Scenes').item.json;
const scene = batchItem;

return [{
  json: {
    scene_id: scene.id,
    topic_id: scene.topic_id,
    project_id: scene.project_id,
    scene_number: scene.scene_number,
    scene_id_text: scene.scene_id,
    narration_text: scene.narration_text,
    visual_type: scene.visual_type,
    chapter: scene.chapter,
    padded_num: String(scene.scene_number).padStart(3, '0'),
    retry_count: 0
  }
}];

// Decode base64 audio and prepare for file write
const audioBase64 = $json.audioContent;
const prevScene = $('Prepare TTS Call').first().json;
const topicId = prevScene.topic_id;
const paddedNum = prevScene.padded_num;

// Convert base64 to binary buffer
const binaryData = Buffer.from(audioBase64, 'base64');

// Store as binary for file write
return [{
  json: {
    scene_id: prevScene.scene_id,
    topic_id: topicId,
    project_id: prevScene.project_id,
    scene_number: prevScene.scene_number,
    padded_num: paddedNum,
    file_path: `/tmp/production/${topicId}/audio/scene_${paddedNum}.mp3`,
    dir_path: `/tmp/production/${topicId}/audio`
  },
  binary: {
    data: {
      data: audioBase64,
      mimeType: 'audio/mpeg',
      fileName: `scene_${paddedNum}.mp3`
    }
  }
}];

// Create audio directory for this topic
const { execSync } = require('child_process');
const topicId = $input.first().json.topic_id;
const dir = '/tmp/production/' + topicId + '/audio';
try {
  execSync('mkdir -p ' + dir);
  console.log('Created dir:', dir);
} catch(e) {
  console.error('mkdir error:', e.message);
}
return $input.all();

// Get audio duration using ffprobe
const { execSync } = require('child_process');
const item = $input.first().json;
const filePath = item.file_path;
let duration = 0;
try {
  const result = execSync(
    'ffprobe -v quiet -show_entries format=duration -of csv=p=0 "' + filePath + '"'
  ).toString().trim();
  duration = parseFloat(result) || 0;
  console.log('Duration:', duration, 'seconds for', filePath);
} catch(e) {
  console.error('ffprobe error:', e.message);
  duration = 0;
}
return [{ json: { ...item, stdout: String(duration), duration_seconds: duration } }];

// Parse FFprobe output and compute timeline
const durationStr = $input.first().json.stdout?.trim() || '0';
const durationSeconds = parseFloat(durationStr);
const durationMs = Math.round(durationSeconds * 1000);

// Get cumulative timeline from state
// We need to track this across iterations
const sceneData = $('Decode Audio').first().json;

// Read the current cumulative from a global variable or compute it
// In n8n, we use $getWorkflowStaticData to persist across loop iterations
const staticData = $getWorkflowStaticData('global');
const startTimeMs = staticData.cumulative_end_time_ms || 0;
const endTimeMs = startTimeMs + durationMs;

// Update static data for next iteration
staticData.cumulative_end_time_ms = endTimeMs;
staticData.scenes_completed = (staticData.scenes_completed || 0) + 1;
staticData.total_tts_cost = (staticData.total_tts_cost || 0) + 0.002;

return [{
  json: {
    scene_id: sceneData.scene_id,
    topic_id: sceneData.topic_id,
    project_id: sceneData.project_id,
    scene_number: sceneData.scene_number,
    padded_num: sceneData.padded_num,
    file_path: sceneData.file_path,
    duration_seconds: durationSeconds,
    audio_duration_ms: durationMs,
    start_time_ms: startTimeMs,
    end_time_ms: endTimeMs,
    scenes_completed: staticData.scenes_completed,
    total_tts_cost: staticData.total_tts_cost
  }
}];

// TTS failed - check retry count
const prevScene = $('Prepare TTS Call').first().json;
const retryCount = prevScene.retry_count || 0;

const errorMsg = $json.error || $json.message || 'TTS API call failed';

return [{
  json: {
    scene_id: prevScene.scene_id,
    topic_id: prevScene.topic_id,
    scene_number: prevScene.scene_number,
    retry_count: retryCount,
    error_message: errorMsg,
    max_retries: 3
  }
}];

// Increment retry count and re-attempt TTS
const data = $input.first().json;
return [{
  json: {
    scene_id: data.scene_id,
    topic_id: data.topic_id,
    project_id: $('Prepare TTS Call').first().json.project_id,
    scene_number: data.scene_number,
    scene_id_text: $('Prepare TTS Call').first().json.scene_id_text,
    narration_text: $('Prepare TTS Call').first().json.narration_text,
    visual_type: $('Prepare TTS Call').first().json.visual_type,
    chapter: $('Prepare TTS Call').first().json.chapter,
    padded_num: $('Prepare TTS Call').first().json.padded_num,
    retry_count: data.retry_count + 1
  }
}];

// Track failed scene in static data
const staticData = $getWorkflowStaticData('global');
staticData.scenes_failed = (staticData.scenes_failed || 0) + 1;

return [{ json: { continue: true } }];

// TTS stopped by user - log and exit
const staticData = $getWorkflowStaticData('global');

return [{
  json: {
    topic_id: $('Set Cumulative Start').item.json.topic_id,
    project_id: $('Set Cumulative Start').item.json.project_id,
    reason: 'stopped_by_user',
    scenes_completed: staticData.scenes_completed || 0,
    scenes_failed: staticData.scenes_failed || 0
  }
}];

// All scenes processed - compile summary
